const item = $input.first();
const input = item && item.json && typeof item.json === 'object' ? item.json : {};

function firstNodeJson(name) {
  try {
    const item = $(name).first();
    return item && item.json && typeof item.json === 'object' ? item.json : {};
  } catch (error) {
    return {};
  }
}

function get(source, keys, fallback = null) {
  for (const key of keys) {
    const val = source[key];
    if (val !== undefined && val !== null && val !== '') return val;
  }
  return fallback;
}

const brief = firstNodeJson('Build Telegram Brief');
const workflow = $workflow;
const error = (input.error && typeof input.error === 'object') ? input.error : {};

const error_type = get(input, ['error_type'], get(error, ['error_type'], 'workflow_error'));
const error_message = get(input, ['error_message', 'error'], get(error, ['error_message', 'error'], null)) ?? 'unknown';
const last_node_executed = $prevNode.name ?? null;
const failure_feedback_enabled = get(input, ['failure_feedback_enabled'], get(error, ['failure_feedback_enabled'], get(brief, ['failure_feedback_enabled'], true)));

const contact_id = get(
  brief,
  ['contact_id', 'telegram_chat_id', 'chatId'],
  get(input, ['contact_id', 'telegram_chat_id', 'chatId'], get(error, ['contact_id', 'telegram_chat_id', 'chatId'], null))
);

const payload = {
  contact_id,
  error_type,
  error_message,
  error_workflow_name: workflow.name,
  last_node_executed,
  failure_feedback_enabled,
};

payload.payload_json = JSON.stringify(payload);

return [{ json: payload }];

const items = $input.all();

function toDisplayText(value) {
  if (value === undefined || value === null) return '';
  if (typeof value === 'string') return value;
  if (typeof value === 'number' || typeof value === 'boolean' || typeof value === 'bigint') return String(value);
  try {
    return JSON.stringify(value);
  } catch (error) {
    return String(value);
  }
}

function escapeHtml(value) {
  return toDisplayText(value)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function safeSheetValue(value) {
  const text = toDisplayText(value);
  if (/^[=+\-@]/.test(text)) return "'" + text;
  return text;
}

function safeSubjectText(value, fallback) {
  const fallbackText = toDisplayText(fallback || 'n8n workflow error')
    .split('')
    .map((char) => {
      const code = char.charCodeAt(0);
      return code < 32 || code === 127 ? ' ' : char;
    })
    .join('')
    .replace(/[<>"]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();

  const text = toDisplayText(value)
    .split('')
    .map((char) => {
      const code = char.charCodeAt(0);
      return code < 32 || code === 127 ? ' ' : char;
    })
    .join('')
    .replace(/[<>"]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();

  const normalized = text || fallbackText || 'n8n workflow error';
  return normalized.length > 120 ? normalized.slice(0, 117).trimEnd() + '...' : normalized;
}

return items.map((item) => {
  const json = item && item.json && typeof item.json === 'object' ? item.json : {};

  return {
    json: {
      ...json,
      safe_contact_id: escapeHtml(json.contact_id),
      safe_error_type: escapeHtml(json.error_type),
      safe_error_message: escapeHtml(json.error_message),
      safe_error_workflow_name: escapeHtml(json.error_workflow_name),
      safe_last_node_executed: escapeHtml(json.last_node_executed),
      safe_execution_id: escapeHtml(json.execution_id),
      safe_execution_url: escapeHtml(json.execution_url),
      safe_payload_json: escapeHtml(json.payload_json),
      sheet_contact_id: safeSheetValue(json.contact_id),
      sheet_error_type: safeSheetValue(json.error_type),
      sheet_error_message: safeSheetValue(json.error_message),
      sheet_error_workflow_name: safeSheetValue(json.error_workflow_name),
      sheet_last_node_executed: safeSheetValue(json.last_node_executed),
      sheet_execution_id: safeSheetValue(json.execution_id),
      sheet_execution_url: safeSheetValue(json.execution_url),
      sheet_payload_json: safeSheetValue(json.payload_json),
      subject_error_type: safeSubjectText(json.error_type, 'workflow_error'),
      subject_error_workflow_name: safeSubjectText(json.error_workflow_name, ''),
    },
  };
});

